input[type="checkbox"] {
    appearance: none;
    -webkit-appearance: none;
    position: relative;
    cursor: pointer;
    vertical-align: middle;
    margin-right: 8px;
    width: 1.25em; /* 使用em单位，使其大小随字体变化 */
    height: 1.25em;
    background: #F8F9FA;
    border-radius: 8px; /* 圆润的方角 */
    border: none;
    box-shadow: 
        2px 2px 5px #e1e3e6,
        -2px -2px 5px #ffffff;
    transition: all 0.2s ease-in-out;
}

input[type="checkbox"]:checked {
    /* 选中时，我们不再改变背景或边框，而是通过伪元素添加标记 */
}

input[type="checkbox"]:checked::after {
    content: '✔'; /* 使用一个简洁的对勾 */
    color: #007AFF; /* 使用一个现代、活力的蓝色作为强调色 */
    font-size: 0.9em;
    font-weight: 900; /* 加粗的勾 */
    position: absolute;
    top: 51%;
    left: 50%;
    transform: translate(-50%, -50%);
    line-height: 1;
}

input[type="checkbox"]:hover {
    transform: translateY(-1px); 
    box-shadow: 
        3px 3px 6px #d9dbe0,
        -3px -3px 6px #ffffff;
}

input[type="checkbox"]:active {
    transform: translateY(0px);
    box-shadow: 
        inset 2px 2px 4px #e1e3e6,
        inset -2px -2px 4px #ffffff;
}

input[type="radio"] {
    appearance: none;
    -webkit-appearance: none;
    position: relative;
    cursor: pointer;
    vertical-align: middle;
    margin-right: 8px;
    width: 1.25em;
    height: 1.25em;
    background: #F8F9FA;
    border-radius: 50%; /* 保持圆形 */
    border: none;
    box-shadow: 
        2px 2px 5px #e1e3e6,
        -2px -2px 5px #ffffff;
    transition: all 0.2s ease-in-out;
}

input[type="radio"]:checked::after {
    content: '';
    width: 0.6em; 
    height: 0.6em;
    border-radius: 50%;
    background-color: #007AFF; 
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
}

input[type="radio"]:hover {
    transform: translateY(-1px);
    box-shadow: 
        3px 3px 6px #d9dbe0,
        -3px -3px 6px #ffffff;
}

input[type="radio"]:active {
    transform: translateY(0px);
    box-shadow: 
        inset 2px 2px 4px #e1e3e6,
        inset -2px -2px 4px #ffffff;
}


input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    width: 100%;
    background: transparent;
    cursor: pointer;
    outline: none;
    padding: 0; 
    box-shadow: none !important;
    filter: none !important;
}

/* A. Webkit浏览器 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;

    height: 45px;
    width: 45px;
    margin-top: 0px; 

    background-image: url('https://files.catbox.moe/aldpk9.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;

    transition: transform 0.2s ease-out;
}

/* B. Firefox浏览器 */
input[type="range"]::-moz-range-thumb {
    height: 45px;
    width: 45px;

    background-image: url('https://files.catbox.moe/aldpk9.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;
    border-radius: 0; 

    transition: transform 0.2s ease-out;
}

/* --- 交互效果 --- */
input[type="range"]:hover::-webkit-slider-thumb {
    transform: scale(1.15); /* 悬停时放大，提供反馈 */
}
input[type="range"]:hover::-moz-range-thumb {
    transform: scale(1.15);
}

input[type="range"]:active::-webkit-slider-thumb {
    transform: scale(1.1); /* 点击拖动时稍微缩小一点，模拟按压感 */
}
input[type="range"]:active::-moz-range-thumb {
    transform: scale(1.1);
}

.menu_button {
    background: transparent !important;
    border: none !important;        
    box-shadow: none !important;      
    border-radius: 12px !important;   
    padding: 8px 12px;                
    margin: 2px;                      
    font-size: 0.9em !important;      
    font-weight: 600 !important;   
    color: #8A9CB1 !important;         
    cursor: pointer;
    transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1); 
    display: inline-flex; 
    align-items: center;
    justify-content: center;
